private void xrTableCell58_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        // --- Declare values --- 
decimal recQty = 0;
decimal DOA = 0;
decimal RejectedQty  = 0;
decimal medicalCondemnation = 0;
decimal pluckReject = 0;

// --- Read values ---
if (GetCurrentColumnValue("RecQty") != null)
    recQty = Convert.ToDecimal(GetCurrentColumnValue("RecQty"));

if (GetCurrentColumnValue("DOA") != null)
    DOA = Convert.ToDecimal(GetCurrentColumnValue("DOA"));

if (GetCurrentColumnValue("RejectedQty") != null)
    RejectedQty = Convert.ToDecimal(GetCurrentColumnValue("RejectedQty"));

if (GetCurrentColumnValue("MedicalCondemnation") != null)
    medicalCondemnation = Convert.ToDecimal(GetCurrentColumnValue("MedicalCondemnation"));

if (GetCurrentColumnValue("PluckReject") != null)
    pluckReject = Convert.ToDecimal(GetCurrentColumnValue("PluckReject"));

// --- Equation ---
decimal result = recQty  - (DOA + RejectedQty ) + medicalCondemnation +pluckReject ;
    recQtyReport += recQty;
    DOAReport += DOA;
    RejectedQtyReport += RejectedQty;
    MedicalCondemnationReport += medicalCondemnation;
    PluckRejectReport += pluckReject;
// --- Add to report total (if required for average/summaries) ---
TotalRecQtyCalc = recQtyReport  - (DOAReport +RejectedQtyReport) + MedicalCondemnationReport +PluckRejectReport ;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##"); // format with up to 2 decimals

}

