private void xrTableCell63_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       // --- Declare values --- 
decimal pluckMedAcc = 0;
decimal counterQty = 0;

// --- Read values ---
if (GetCurrentColumnValue("PluckMedAcc") != null)
    pluckMedAcc = Convert.ToDecimal(GetCurrentColumnValue("PluckMedAcc"));

if (GetCurrentColumnValue("CounterQty") != null)
    counterQty = Convert.ToDecimal(GetCurrentColumnValue("CounterQty"));

// --- Equation ---
decimal result = pluckMedAcc - counterQty;

// --- Add to report total (if required for summaries/averages) ---
    pluckMedAccReportDiff += pluckMedAcc;
    counterQtyReportDiff += counterQty;

TotalPluckMedAccMinusCounterQty = pluckMedAccReportDiff  - counterQtyReportDiff  ;
// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("0.##"); // format with up to 2 decimals

}

